import React from 'react';
import './KhaiBaoCoSo.css'; // Vẫn giữ lại CSS để kiểm tra

function KhaiBaoCoSo() {
  // Thêm log này để chắc chắn component được gọi
  console.log("Đang render KhaiBaoCoSo - Phiên bản KIỂM TRA");

  return (
    <div className="khai-bao-container">
      <h1>TEST - Trang Khai Báo Cơ Sở</h1>
      <p style={{ fontSize: '18px', color: 'green', fontWeight: 'bold' }}>
        Nếu bạn thấy được dòng chữ này, có nghĩa là component đã render thành công.
      </p>
      <p>
        Vấn đề nằm ở một trong các logic phức tạp (state, effect, form...) mà chúng ta đã tạm ẩn đi.
      </p>
    </div>
  );
}

export default KhaiBaoCoSo;
